{
  "title": "संदर्भ बजट",
  "group": "टोकन प्रबंधन",
  "options": [
    {
      "text": "जानकारी को अधिकतम करने के लिए संदर्भ विंडो का 95%+ उपयोग करें"
    },
    {
      "text": "पूरी विंडो भरने के बजाय आउटपुट के लिए सार्थक हेडरूम रखें"
    },
    {
      "text": "संदर्भ बजट केवल 32K टोकन से कम वाले मॉडलों के लिए मायने रखता है"
    },
    {
      "text": "जब विंडो पार हो जाती है तो मॉडल स्वचालित रूप से छोटा कर देता है"
    }
  ],
  "questionProse": [
    "पुनर्प्राप्त संदर्भ के साथ RAG प्रॉम्प्ट बनाते समय, संदर्भ बजट के लिए एक अच्छा सामान्य नियम है:"
  ],
  "explanationProse": [
    "संदर्भ विंडो **इनपुट और आउटपुट** के बीच साझा होती है। यदि आप इनपुट के लिए 90% उपयोग करते हैं, तो मॉडल के पास प्रतिक्रिया उत्पन्न करने के लिए केवल 10% विंडो बचती है — जिसके परिणामस्वरूप अक्सर छोटे या खराब आउटपुट मिलते हैं।\n\n    एक उचित अनुमान: पहले अपेक्षित आउटपुट आकार तय करें, फिर अपने इनपुट को शेष बजट से आरामदायक रूप से नीचे रखें। कई RAG कार्यों के लिए, इसका मतलब है कि **कुल संदर्भ विंडो का 60–70% से अधिक इनपुट के लिए उपयोग न करें** (सिस्टम प्रॉम्प्ट + इतिहास + पुनर्प्राप्त संदर्भ)। बाकी को जनरेशन और सुरक्षा मार्जिन के लिए छोड़ दें।\n\n    इसके अतिरिक्त, मॉडल अपनी संदर्भ विंडो के किनारों के पास खराब प्रदर्शन करते हैं — जैसे-जैसे संदर्भ भरता है, समझ और निर्देश-पालन कम होता जाता है। 95% पर चलाना तकनीकी रूप से संभव है। यह 50% पर चलने जैसा अनुभव नहीं है।"
  ]
}
